import{_ as a,o,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Custom QR Code Download Improvements","description":"","frontmatter":{"title":"Custom QR Code Download Improvements","slug":"custom-qr-code-download-improvements"},"headers":[],"relativePath":"account-hub/custom-qr-code-download-improvements.md","filePath":"account-hub/custom-qr-code-download-improvements.md"}'),i={name:"account-hub/custom-qr-code-download-improvements.md"};function s(n,e,l,c,d,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<p>Branch Custom QR Code customers now have access to higher-resolution custom Branch QR Codes, as well as the ability to download them in SVG format.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Custom Branch QR Codes are getting a significant upgrade in the quality of the image that gets downloaded during creation.</p><p>They can also now be downloaded in three different file formats: PNG, JPEG, and SVG.</p><p>.png)</p><h2 id="image-quality" tabindex="-1">Image Quality <a class="header-anchor" href="#image-quality" aria-label="Permalink to &quot;Image Quality&quot;">​</a></h2><p>The Branch QR Code image resolution is increasing to <strong>300 pixels per inch</strong> and the image size is increasing to <strong>1667 x 1667 pixels</strong>.</p><p>This improves the reliability of the Branch QR Code when it comes to scanning it via device cameras, whether presented digitally or in printed materials.</p><h2 id="svg-file-format" tabindex="-1">SVG File Format <a class="header-anchor" href="#svg-file-format" aria-label="Permalink to &quot;SVG File Format&quot;">​</a></h2><p>By popular request, Branch has introduced SVG files as an option for Branch QR Codes.</p><p>SVG (which stands for Scalable Vector Graphics) files are best used when being able to resize the image without losing quality is essential. This could include high-quality print materials (posters, flyers, large banners) or certain websites.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to Custom QR Codes requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>To learn more about Branch QR Code creation, visit our <a href="./create-qr-codes.html">guide</a>.</p>',15)])])}const p=a(i,[["render",s]]);export{u as __pageData,p as default};
